<script lang="ts">import { Ban, CheckCircle2, CircleAlert, LoaderCircle, RefreshCw } from '@lucide/svelte';import { api } from '$lib/api';import { appState } from '$lib/app-state.svelte';async function cancel(id:string){await api(`/jobs/${id}/cancel`,{method:'POST'});await appState.refresh()}</script>
<div class="mx-auto max-w-7xl"><header class="flex items-end justify-between"><div><div class="eyebrow">Activity & logs</div><h1 class="mt-2 text-4xl font-semibold">Background work</h1><p class="muted mt-3">Durable jobs survive browser navigation and report replayable progress.</p></div><button onclick={()=>appState.refresh()} class="flex items-center gap-2 rounded-xl border border-[var(--line)] px-4 py-2.5 text-sm font-semibold"><RefreshCw size={16}/> Refresh</button></header><div class="surface mt-7 overflow-hidden rounded-2xl">{#each appState.jobs as job}<article class="flex flex-wrap items-center gap-4 border-b border-[var(--line)] p-4 last:border-0">{#if ['running','queued','cancel_requested'].includes(job.status)}<LoaderCircle class="animate-spin text-[var(--accent)]" size={19}/>{:else if job.status==='succeeded'}<CheckCircle2 class="text-[var(--success)]" size={19}/>{:else}<CircleAlert class="text-red-500" size={19}/>{/if}<div class="min-w-0 flex-1"><div class="truncate font-semibold">{job.kind}</div><div class="muted mt-1 text-xs">{job.status} · {new Date(job.created_at).toLocaleString()}</div>{#if job.error_message}<p class="mt-1 text-xs text-red-500">{job.error_message}</p>{/if}</div><div class="w-32"><div class="h-1.5 overflow-hidden rounded-full bg-[var(--line)]"><div class="h-full bg-[var(--accent)]" style={`width:${job.progress*100}%`}></div></div><div class="muted mt-1 text-right text-[.65rem]">{Math.round(job.progress*100)}%</div></div>{#if ['running','queued'].includes(job.status)}<button onclick={()=>cancel(job.id)} class="flex items-center gap-1 rounded-lg border border-red-400/40 px-3 py-2 text-xs font-semibold text-red-500"><Ban size={14}/> Cancel</button>{/if}</article>{:else}<div class="muted p-10 text-center">No jobs recorded.</div>{/each}</div></div>
